import React, { useState, useEffect } from 'react';
import axios from 'axios';
import TopNavBar from './components/TopNavBar';
import Hero from './components/Hero';
import MovieCard from './components/MovieCard';
import Footer from './components/Footer';
import './index.css';

function App() {
  const [searchQuery, setSearchQuery] = useState('');
  const [primaryMovie, setPrimaryMovie] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // For the "Continue Watching" section, we'll use some default/placeholder data 
  // until the user searches for something.
  const [continueWatching, setContinueWatching] = useState([
    { title: "Carbon Altered", similarity: 0.92 },
    { title: "Mars Protocol", similarity: 0.88 },
    { title: "Midnight City", similarity: 0.95 },
    { title: "Zenith Chronicles", similarity: 0.82 }
  ]);

  const handleSearch = async (query) => {
    if (!query.trim()) return;

