      setRecommendations(response.data.recommendations || []);
      // Auto-scroll to hero when search completes
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
      console.error(err);
      setError(err.response?.status === 404 ? "Movie not found!" : "Backend connection failed.");
    } finally {
      setLoading(false);
    }
  };

